{"content":"import { GoogleGenAI, Type, Schema } from "@google/genai";

// Helper to safely get env var
const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// Helper to simulate delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// ─── Interfaces ────────────────────────────────────────────────────────────────

export interface AIEngineResponse {
  engine: 'ChatGPT' | 'Claude' | 'Perplexity' | 'Gemini' | 'AI Overviews';
  response: string;
  mentionType: 'direct' | 'indirect' | 'comparison' | 'absent';
  mentionScore: number;
  sentiment: 'positive' | 'neutral' | 'negative';
  citationPresent: boolean;
  excerpt: string;
}

export interface CitationSimulationResult {
  query: string;
  brandName: string;
  brandUrl: string;
  overallScore: number;
  engines: AIEngineResponse[];
  improvements: string[];
  competitorsMentioned: string[];
}

// ─── Industry competitor mapping ───────────────────────────────────────────────

const INDUSTRY_COMPETITORS: Record<string, string[]> = {
  saas: ['HubSpot', 'Salesforce', 'Monday.com', 'Notion', 'Airtable', 'Zendesk'],
  ecommerce: ['Shopify', 'WooCommerce', 'BigCommerce', 'PrestaShop', 'Magento'],
  marketing: ['SEMrush', 'Ahrefs', 'Moz', 'Mailchimp', 'HubSpot', 'Buffer'],
  finance: ['Stripe', 'PayPal', 'Square', 'Wise', 'Revolut', 'Qonto'],
  sante: ['Doctolib', 'Qare', 'Alan', 'Livi', 'Maiia'],
  immobilier: ['SeLoger', 'LeBonCoin', 'Bien\'ici', 'MeilleursAgents', 'PAP'],
  education: ['Coursera', 'Udemy', 'OpenClassrooms', 'Skillshare', 'LinkedIn Learning'],
  restauration: ['TheFork', 'Uber Eats', 'Deliveroo', 'Zenchef', 'Lightspeed'],
  juridique: ['LegalStart', 'Captain Contrat', 'Legalplace', 'Rocket Lawyer'],
  default: ['HubSpot', 'Salesforce', 'Stripe', 'Notion', 'Ahrefs'],
};

const getCompetitors = (industry?: string): string[] => {
  if (!industry) return INDUSTRY_COMPETITORS.default;
  const key = industry.toLowerCase().trim();
  return INDUSTRY_COMPETITORS[key] || INDUSTRY_COMPETITORS.default;
};

// ─── Fallback simulation (no API key) ──────────────────────────────────────────

const fallbackSimulation = async (
  query: string,
  brandName: string,
  brandUrl: string,
  industry?: string
): Promise<CitationSimulationResult> => {
  // Simulate processing time
  await delay(3000);

  const competitors = getCompetitors(industry);
  const hostname = new URL(brandUrl).hostname;
  const industryLabel = industry || 'technology';

  // Pick 3 competitors to mention across engines
  const mentionedCompetitors = competitors.slice(0, 3);

  // ── ChatGPT response: conversational tone ──
  const chatgptResponse: AIEngineResponse = {
    engine: 'ChatGPT',
    response: `Great question! When it comes to ${query}, there are several strong options in the ${industryLabel} space. ${mentionedCompetitors[0]} and ${mentionedCompetitors[1]} are widely recognized leaders that many businesses rely on. ${brandName} is also worth considering — they've been gaining traction with a focused approach to the problem. I'd recommend evaluating each based on your specific needs, budget, and team size to find the best fit.`,
    mentionType: 'indirect',
    mentionScore: 35,
    sentiment: 'neutral',
    citationPresent: false,
    excerpt: `${brandName} is also worth considering — they've been gaining traction with a focused approach to the problem.`,
  };

  // ── Claude response: analytical and structured ──
  const claudeResponse: AIEngineResponse = {
    engine: 'Claude',
    response: `Analyzing the ${industryLabel} landscape for "${query}", the market can be segmented into three tiers. Enterprise-grade solutions include ${mentionedCompetitors[0]} and ${mentionedCompetitors[1]}, which offer comprehensive feature sets but at higher price points. Mid-market alternatives such as ${mentionedCompetitors[2]} provide a balanced cost-to-value ratio. I don't have specific verified data about ${brandName} in my training set, so I'd recommend checking their website directly at ${hostname} for the most current information on their capabilities and positioning.`,
    mentionType: 'indirect',
    mentionScore: 20,
    sentiment: 'neutral',
    citationPresent: false,
    excerpt: `I don't have specific verified data about ${brandName} in my training set, so I'd recommend checking their website directly at ${hostname}.`,
  };

  // ── Perplexity response: includes source citations ──
  const perplexityResponse: AIEngineResponse = {
    engine: 'Perplexity',
    response: `Based on recent analysis, the top solutions for ${query} in ${industryLabel} include ${mentionedCompetitors[0]} (ranked #1 by G2 in 2025) and ${mentionedCompetitors[1]} [1]. ${mentionedCompetitors[2]} is also frequently recommended for mid-size businesses [2]. ${brandName} does not currently appear in major comparison rankings for this category, though their website (${hostname}) indicates active development in this space [3].\n\nSources:\n[1] g2.com/categories/${industryLabel}\n[2] capterra.com/reviews\n[3] ${hostname}`,
    mentionType: 'absent',
    mentionScore: 10,
    sentiment: 'neutral',
    citationPresent: true,
    excerpt: `${brandName} does not currently appear in major comparison rankings for this category.`,
  };

  // ── Gemini response: factual and data-driven ──
  const geminiResponse: AIEngineResponse = {
    engine: 'Gemini',
    response: `For "${query}", the ${industryLabel} market in 2025 is valued at approximately $XX billion globally. The primary vendors are ${mentionedCompetitors[0]} (market share ~25%), ${mentionedCompetitors[1]} (~18%), and ${mentionedCompetitors[2]} (~12%). ${brandName} is a newer entrant in this segment. According to available data, they offer services through ${hostname}, though detailed market share figures and independent reviews are limited at this time. Key selection criteria include pricing, integration capabilities, and customer support quality.`,
    mentionType: 'direct',
    mentionScore: 40,
    sentiment: 'neutral',
    citationPresent: false,
    excerpt: `${brandName} is a newer entrant in this segment. According to available data, they offer services through ${hostname}, though detailed market share figures and independent reviews are limited.`,
  };

  // ── AI Overviews response: factual snippet with source links ──
  const aiOverviewsResponse: AIEngineResponse = {
    engine: 'AI Overviews',
    response: `${query}\n\nAccording to multiple sources, the leading solutions in ${industryLabel} include ${mentionedCompetitors[0]} and ${mentionedCompetitors[1]}. ${brandName} (${hostname}) is referenced as a specialized provider in this space, offering focused capabilities for ${industryLabel} professionals.\n\n• ${mentionedCompetitors[0]} — Enterprise-grade solution\n• ${mentionedCompetitors[1]} — Popular mid-market option\n• ${brandName} — Specialized ${industryLabel} tool\n\nSources: ${hostname}, g2.com, capterra.com`,
    mentionType: 'comparison',
    mentionScore: 45,
    sentiment: 'neutral',
    citationPresent: true,
    excerpt: `${brandName} (${hostname}) is referenced as a specialized provider in this space.`,
  };

  const engines: AIEngineResponse[] = [
    chatgptResponse,
    claudeResponse,
    perplexityResponse,
    geminiResponse,
    aiOverviewsResponse,
  ];

  // Calculate overall score as the average of all engine mention scores
  const overallScore = Math.round(
    engines.reduce((sum, e) => sum + e.mentionScore, 0) / engines.length
  );

  // Improvement suggestions
  const improvements: string[] = [
    `Create a comprehensive "About" page on ${hostname} with structured data (Schema.org Organization) so AI models can extract authoritative entity information.`,
    `Publish original research, benchmarks, or case studies related to "${query}" to build topical authority that AI engines reference.`,
    `Ensure ${brandName} is listed on major comparison platforms (G2, Capterra, TrustPilot) with verified reviews — Perplexity and ChatGPT heavily rely on these sources.`,
    `Add FAQ sections with "Answer-First" formatting on key landing pages to increase the probability of direct AI citations.`,
    `Build backlinks from authoritative industry publications and directories so AI models associate ${brandName} with the "${industryLabel}" topic cluster.`,
    `Implement llms.txt and llms-full.txt files at ${hostname}/llms.txt to provide AI crawlers with a structured, canonical source of truth about your brand.`,
  ];

  return {
    query,
    brandName,
    brandUrl,
    overallScore,
    engines,
    improvements,
    competitorsMentioned: mentionedCompetitors,
  };
};

// ─── Gemini API call ───────────────────────────────────────────────────────────

const simulateWithGemini = async (
  query: string,
  brandName: string,
  brandUrl: string,
  industry?: string
): Promise<CitationSimulationResult> => {
  const apiKey = getApiKey();
  if (!apiKey) {
    throw new Error("No API key available");
  }

  const ai = new GoogleGenAI({ apiKey });

  const engineResponseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      engine: {
        type: Type.STRING,
        enum: ['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'],
        description: "The AI engine being simulated",
      },
      response: {
        type: Type.STRING,
        description: "The simulated AI response text (3-5 sentences). ChatGPT: conversational. Claude: analytical and structured. Perplexity: include source citation format [1][2]. Gemini: factual and data-driven.",
      },
      mentionType: {
        type: Type.STRING,
        enum: ['direct', 'indirect', 'comparison', 'absent'],
        description: "How the brand is mentioned: direct (by name in context), indirect (alluded to), comparison (mentioned alongside competitors), absent (not mentioned)",
      },
      mentionScore: {
        type: Type.NUMBER,
        description: "0-100 score of how prominently the brand is featured in the response",
      },
      sentiment: {
        type: Type.STRING,
        enum: ['positive', 'neutral', 'negative'],
        description: "Sentiment of the mention toward the brand",
      },
      citationPresent: {
        type: Type.BOOLEAN,
        description: "Whether the engine includes a source citation or link for the brand",
      },
      excerpt: {
        type: Type.STRING,
        description: "The specific part of the response that mentions the brand, or empty string if absent",
      },
    },
    required: ['engine', 'response', 'mentionType', 'mentionScore', 'sentiment', 'citationPresent', 'excerpt'],
  };

  const resultSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      overallScore: {
        type: Type.NUMBER,
        description: "0-100 average visibility score across all engines",
      },
      engines: {
        type: Type.ARRAY,
        items: engineResponseSchema,
        description: "Simulated responses from 5 AI engines: ChatGPT, Claude, Perplexity, Gemini, AI Overviews",
      },
      improvements: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "4-6 actionable improvement suggestions to increase AI citation visibility",
      },
      competitorsMentioned: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Names of competitors mentioned across the simulated responses",
      },
    },
    required: ['overallScore', 'engines', 'improvements', 'competitorsMentioned'],
  };

  const industryContext = industry ? `The brand operates in the "${industry}" industry.` : '';

  const prompt = `
    CONTEXT:
    You are an expert in AI visibility and Answer Engine Optimization (AEO).
    A user wants to understand how different AI engines would respond to a query about their brand.

    INPUTS:
    - User query: "${query}"
    - Brand name: "${brandName}"
    - Brand URL: ${brandUrl}
    ${industryContext}

    MISSION:
    Simulate how each of the 5 major AI engines (ChatGPT, Claude, Perplexity, Gemini, AI Overviews) would realistically respond to the query "${query}".

    RULES FOR EACH ENGINE:
    1. **ChatGPT**: Conversational, friendly tone. May mention the brand if it has strong web presence. Tends to recommend well-known solutions first.
    2. **Claude**: Analytical, structured analysis. Cautious about unverified claims. Will note if it lacks training data on the brand.
    3. **Perplexity**: Always includes numbered source citations [1][2][3]. Relies heavily on indexed web sources, comparison sites, and reviews.
    4. **Gemini**: Factual, data-driven. Focuses on market data, statistics, and objective comparisons.
    5. **AI Overviews**: Google's AI-generated SERP snippet. Short, factual answer-box format with bullet points and source links. Tends to cite sources directly and use comparison/list format.

    IMPORTANT:
    - Be realistic: if the brand is not well-known, some engines should NOT mention it or mention it minimally.
    - Each response should be 3-5 sentences of natural AI-style text.
    - Vary the mentionType across engines (not all should be the same).
    - Include real competitor names relevant to the industry.
    - Provide 4-6 specific, actionable improvement suggestions.
    - The overallScore should reflect the average mentionScore across engines.

    Respond strictly in the JSON schema provided.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: resultSchema,
      temperature: 0.4,
    },
  });

  let output = response.text;
  if (!output) {
    throw new Error("Empty response from AI");
  }

  // Clean up potentially leaked markdown fences despite JSON mode
  output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  const jsonResponse = JSON.parse(output);

  return {
    query,
    brandName,
    brandUrl,
    overallScore: jsonResponse.overallScore,
    engines: jsonResponse.engines,
    improvements: jsonResponse.improvements,
    competitorsMentioned: jsonResponse.competitorsMentioned,
  };
};

// ─── Main exported function ────────────────────────────────────────────────────

export const simulateCitation = async (
  query: string,
  brandName: string,
  brandUrl: string,
  industry?: string
): Promise<CitationSimulationResult> => {
  const apiKey = getApiKey();

  if (!apiKey) {
    console.warn("API_KEY not found or process.env unavailable, using fallback simulation.");
    return fallbackSimulation(query, brandName, brandUrl, industry);
  }

  try {
    return await simulateWithGemini(query, brandName, brandUrl, industry);
  } catch (error) {
    console.error("AI Citation Simulation failed:", error);
    return fallbackSimulation(query, brandName, brandUrl, industry);
  }
};
"}

{"content":"import { GoogleGenAI } from "@google/genai";
import {
  MonitoringResult,
  CitationEntry,
  EngineResult,
  CompetitorData,
  TimeSeriesPoint,
  AIEngine,
  Sentiment,
  SentimentBreakdown,
} from "../types/ai-monitoring";

const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// ── Deterministic helpers ──
const seededRandom = (seed: number, offset: number): number => {
  const raw = ((seed * 37 + offset * 19 + 11) * 17) % 1000;
  return raw / 1000;
};

const seededInt = (seed: number, offset: number, min: number, max: number): number => {
  return min + Math.round(seededRandom(seed, offset) * (max - min));
};

const seededFloat = (seed: number, offset: number, min: number, max: number): number => {
  return Math.round((min + seededRandom(seed, offset) * (max - min)) * 10) / 10;
};

// ── Fallback deterministic simulation ──
const fallbackSimulation = async (brandName: string, url: string, period: '7d' | '30d' | '90d' = '30d'): Promise<MonitoringResult> => {
  await new Promise(resolve => setTimeout(resolve, 2400));

  let hostname: string;
  try { hostname = new URL(url).hostname; } catch { hostname = url; }
  const brand = brandName || hostname;
  const seed = brand.length + hostname.length;

  const periodDays = period === '7d' ? 7 : period === '30d' ? 30 : 90;
  const multiplier = period === '7d' ? 1 : period === '30d' ? 3.5 : 10;

  // ── Total citations & KPIs ──
  const totalCitations = seededInt(seed, 1, Math.round(12 * multiplier), Math.round(45 * multiplier));
  const shareOfVoice = seededFloat(seed, 2, 8, 42);
  const trend = seededFloat(seed, 3, -15, 25);

  const overallSentiment: SentimentBreakdown = {
    positive: seededInt(seed, 4, 35, 65),
    neutral: seededInt(seed, 5, 20, 40),
    negative: 0,
  };
  overallSentiment.negative = 100 - overallSentiment.positive - overallSentiment.neutral;
  if (overallSentiment.negative < 0) {
    overallSentiment.neutral += overallSentiment.negative;
    overallSentiment.negative = 0;
  }

  // ── Engine results ──
  const engines: AIEngine[] = ['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'];
  const queryPool = [
    `meilleur ${brand.split('.')[0]} avis`,
    `${brand.split('.')[0]} vs concurrent`,
    `alternative a ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} prix tarif`,
    `${brand.split('.')[0]} fiabilite`,
    `comparatif ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} guide complet`,
    `recommandation ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} pour entreprise`,
    `top solutions ${brand.split('.')[0]}`,
    `${brand.split('.')[0]} expertise`,
    `${brand.split('.')[0]} retour experience`,
  ];

  const engineResults: EngineResult[] = engines.map((engine, i) => {
    const engineCitations = seededInt(seed, 10 + i, Math.round(3 * multiplier), Math.round(15 * multiplier));
    const engineSov = seededFloat(seed, 20 + i, 5, 45);
    const engineSentiment: SentimentBreakdown = {
      positive: seededInt(seed, 30 + i, 30, 70),
      neutral: seededInt(seed, 40 + i, 15, 40),
      negative: 0,
    };
    engineSentiment.negative = Math.max(0, 100 - engineSentiment.positive - engineSentiment.neutral);
    if (engineSentiment.negative < 0) {
      engineSentiment.neutral += engineSentiment.negative;
      engineSentiment.negative = 0;
    }

    const topQueries = queryPool
      .sort(() => seededRandom(seed, 50 + i * 10) - 0.5)
      .slice(0, seededInt(seed, 60 + i, 3, 5));

    return {
      engine,
      totalCitations: engineCitations,
      shareOfVoice: engineSov,
      avgPosition: seededFloat(seed, 70 + i, 1, 5),
      sentiment: engineSentiment,
      trend: seededFloat(seed, 80 + i, -20, 30),
      topQueries,
    };
  });

  // ── Citations table ──
  const sentiments: Sentiment[] = ['positive', 'neutral', 'negative'];
  const citationCount = Math.min(totalCitations, 20);
  const citations: CitationEntry[] = Array.from({ length: citationCount }, (_, i) => {
    const engineIndex = i % 5;
    const sentimentIndex = seededInt(seed, 100 + i, 0, 2);
    const daysAgo = seededInt(seed, 120 + i, 0, periodDays - 1);
    const date = new Date();
    date.setDate(date.getDate() - daysAgo);

    return {
      id: `cit-${seed}-${i}`,
      engine: engines[engineIndex],
      query: queryPool[i % queryPool.length],
      position: seededInt(seed, 140 + i, 1, 8),
      date: date.toISOString().split('T')[0],
      sentiment: sentiments[sentimentIndex],
      snippet: generateSnippet(brand, engines[engineIndex], sentiments[sentimentIndex], seed + i),
      confidence: seededInt(seed, 160 + i, 60, 98),
    };
  }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // ── Competitors ──
  const competitorNames = [
    'CompetitorAlpha', 'RivalTech', 'MarketLeader', 'IndustryStar', 'NextGenCorp'
  ];
  const competitors: CompetitorData[] = competitorNames.slice(0, 4).map((name, i) => ({
    name,
    totalCitations: seededInt(seed, 200 + i, Math.round(8 * multiplier), Math.round(50 * multiplier)),
    shareOfVoice: seededFloat(seed, 210 + i, 5, 35),
    avgSentiment: seededInt(seed, 220 + i, 40, 85),
    trend: seededFloat(seed, 230 + i, -20, 30),
    dominantEngine: engines[seededInt(seed, 240 + i, 0, 4)],
  }));

  // ── Time series ──
  const timeSeries: TimeSeriesPoint[] = Array.from({ length: periodDays }, (_, i) => {
    const date = new Date();
    date.setDate(date.getDate() - (periodDays - 1 - i));
    const daySeed = seed + i * 7;
    const chatgpt = seededInt(daySeed, 300, 0, 5);
    const claude = seededInt(daySeed, 310, 0, 4);
    const perplexity = seededInt(daySeed, 320, 0, 4);
    const gemini = seededInt(daySeed, 330, 0, 3);
    const aiOverviews = seededInt(daySeed, 340, 0, 4);
    return {
      date: date.toISOString().split('T')[0],
      citations: chatgpt + claude + perplexity + gemini + aiOverviews,
      chatgpt,
      claude,
      perplexity,
      gemini,
      aiOverviews,
    };
  });

  // ── Summary & recommendations ──
  const summary = totalCitations > 80
    ? `${brand} beneficie d'une excellente visibilite sur les moteurs IA avec ${totalCitations} citations detectees sur ${periodDays} jours. Le sentiment est majoritairement positif (${overallSentiment.positive}%). La part de voix de ${shareOfVoice}% positionne la marque parmi les leaders cites.`
    : totalCitations > 30
      ? `${brand} a une visibilite moderee sur les IA generatives avec ${totalCitations} citations sur ${periodDays} jours. Le Share of Voice de ${shareOfVoice}% offre une marge de progression. Concentrez vos efforts sur les moteurs ou la marque est sous-representee.`
      : `${brand} a une faible presence dans les reponses IA (${totalCitations} citations sur ${periodDays} jours). La part de voix de ${shareOfVoice}% indique un besoin urgent d'optimisation AEO pour ameliorer la citabilite de la marque.`;

  const recommendations = [
    'Enrichir le contenu du site avec des donnees factuelles et structurees (Schema.org) pour ameliorer la citabilite.',
    'Creer des pages "hub" thematiques qui repondent directement aux questions frequentes detectees.',
    'Renforcer les signaux E-E-A-T (bios auteur, certifications, avis clients) pour gagner en autorite.',
    'Publier du contenu regulier sur les sujets ou la marque est citee pour maintenir la visibilite.',
    'Optimiser le fichier llms.txt pour guider les IA sur les informations cles de la marque.',
  ];

  return {
    brandName: brand,
    url,
    scanDate: new Date().toISOString(),
    period,
    totalCitations,
    shareOfVoice,
    overallSentiment,
    trend,
    engineResults,
    citations,
    competitors,
    timeSeries,
    summary,
    recommendations,
  };
};

function generateSnippet(brand: string, engine: AIEngine, sentiment: Sentiment, seed: number): string {
  const positiveSnippets = [
    `${brand} est frequemment recommande pour sa fiabilite et son expertise dans le domaine.`,
    `Selon les retours, ${brand} offre un excellent rapport qualite-prix et un service client reactif.`,
    `${brand} se distingue par son approche innovante et ses resultats prouves aupres de ses clients.`,
    `Les utilisateurs saluent la qualite de service de ${brand} et son expertise reconnue.`,
  ];
  const neutralSnippets = [
    `${brand} fait partie des acteurs du marche avec une offre competitive.`,
    `${brand} propose des services comparables aux standards de l'industrie.`,
    `Parmi les options disponibles, ${brand} est mentionne comme une alternative a considerer.`,
    `${brand} est present sur ce segment avec une offre qui repond aux besoins standards.`,
  ];
  const negativeSnippets = [
    `Certains utilisateurs rapportent des delais chez ${brand}, bien que la qualite soit reconnue.`,
    `${brand} pourrait ameliorer certains aspects de son service pour rester competitif.`,
    `Des alternatives a ${brand} existent pour ceux qui cherchent un meilleur rapport qualite-prix.`,
  ];

  const pool = sentiment === 'positive' ? positiveSnippets : sentiment === 'neutral' ? neutralSnippets : negativeSnippets;
  const idx = seed % pool.length;
  return pool[idx];
}

// ── Main export ──
export const runMonitoringScan = async (
  brandName: string,
  url: string,
  period: '7d' | '30d' | '90d' = '30d'
): Promise<MonitoringResult> => {
  const apiKey = getApiKey();
  if (!apiKey) {
    console.warn("API_KEY not found, using simulation.");
    return fallbackSimulation(brandName, url, period);
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `Tu es un expert en monitoring de visibilite de marque sur les moteurs de reponse IA (ChatGPT, Claude, Perplexity, Gemini, AI Overviews).

Analyse la marque "${brandName}" (${url}) et genere un rapport de monitoring IA complet pour les ${period === '7d' ? '7 derniers jours' : period === '30d' ? '30 derniers jours' : '90 derniers jours'}.

Genere un JSON avec:
- totalCitations: nombre total de citations detectees
- shareOfVoice: pourcentage de part de voix (0-100)
- overallSentiment: { positive: number, neutral: number, negative: number } (somme = 100)
- trend: evolution en % vs periode precedente
- engineResults: tableau de 5 objets (ChatGPT, Claude, Perplexity, Gemini, AI Overviews) avec totalCitations, shareOfVoice, avgPosition, sentiment, trend, topQueries
- citations: tableau de 15-20 citations recentes avec engine, query, position, date, sentiment, snippet, confidence
- competitors: tableau de 4 concurrents avec name, totalCitations, shareOfVoice, avgSentiment, trend, dominantEngine
- timeSeries: tableau de points jour par jour avec date, citations, chatgpt, claude, perplexity, gemini, aiOverviews
- summary: resume en francais de la visibilite IA
- recommendations: 5 recommandations actionables en francais

Reponds UNIQUEMENT avec le JSON valide.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        temperature: 0.4,
      }
    });

    let output = response.text;
    if (!output) throw new Error("Empty response");
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const parsed = JSON.parse(output);
    return {
      brandName,
      url,
      scanDate: new Date().toISOString(),
      period,
      ...parsed,
    };
  } catch (error) {
    console.error("AI Monitoring scan failed:", error);
    return fallbackSimulation(brandName, url, period);
  }
};
