{"content":"import {
  ApiKey,
  ApiEndpoint,
  ApiUsageDay,
  ApiUsageStats,
  Webhook,
  WebhookEvent,
} from '../types/api-developer';

const STORAGE_KEYS = {
  apiKeys: 'citedby_api_keys',
  webhooks: 'citedby_webhooks',
};

// ── Helpers ──

const generateId = (): string =>
  `${Date.now()}_${Math.random().toString(36).substring(2, 10)}`;

const generateHex = (length: number): string => {
  const chars = '0123456789abcdef';
  let result = '';
  for (let i = 0; i < length; i++) {
    result += chars[Math.floor(Math.random() * chars.length)];
  }
  return result;
};

// ── API Keys ──

export const getApiKeys = (): ApiKey[] => {
  try {
    const raw = localStorage.getItem(STORAGE_KEYS.apiKeys);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
};

const saveApiKeys = (keys: ApiKey[]): void => {
  localStorage.setItem(STORAGE_KEYS.apiKeys, JSON.stringify(keys));
};

export const createApiKey = (name: string): ApiKey => {
  const newKey: ApiKey = {
    id: generateId(),
    name,
    key: `cb_live_${generateHex(32)}`,
    createdAt: new Date().toISOString(),
    status: 'active',
  };
  const keys = getApiKeys();
  keys.unshift(newKey);
  saveApiKeys(keys);
  return newKey;
};

export const revokeApiKey = (id: string): void => {
  const keys = getApiKeys().map((k) =>
    k.id === id ? { ...k, status: 'revoked' as const } : k
  );
  saveApiKeys(keys);
};

export const regenerateApiKey = (id: string): ApiKey | null => {
  const keys = getApiKeys();
  const index = keys.findIndex((k) => k.id === id);
  if (index === -1) return null;
  const updated: ApiKey = {
    ...keys[index],
    key: `cb_live_${generateHex(32)}`,
    createdAt: new Date().toISOString(),
    status: 'active',
  };
  keys[index] = updated;
  saveApiKeys(keys);
  return updated;
};

// ── Webhooks ──

export const getWebhooks = (): Webhook[] => {
  try {
    const raw = localStorage.getItem(STORAGE_KEYS.webhooks);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
};

const saveWebhooks = (webhooks: Webhook[]): void => {
  localStorage.setItem(STORAGE_KEYS.webhooks, JSON.stringify(webhooks));
};

export const createWebhook = (url: string, events: WebhookEvent[]): Webhook => {
  const webhook: Webhook = {
    id: generateId(),
    url,
    events,
    active: true,
    lastDelivery: null,
    createdAt: new Date().toISOString(),
  };
  const webhooks = getWebhooks();
  webhooks.unshift(webhook);
  saveWebhooks(webhooks);
  return webhook;
};

export const deleteWebhook = (id: string): void => {
  const webhooks = getWebhooks().filter((w) => w.id !== id);
  saveWebhooks(webhooks);
};

export const toggleWebhook = (id: string): Webhook | null => {
  const webhooks = getWebhooks();
  const index = webhooks.findIndex((w) => w.id === id);
  if (index === -1) return null;
  webhooks[index] = { ...webhooks[index], active: !webhooks[index].active };
  saveWebhooks(webhooks);
  return webhooks[index];
};

// ── Static Endpoints ──

export const getEndpoints = (): ApiEndpoint[] => [
  {
    method: 'GET',
